    <div class="frame-container">
      <span class="frame-label">04 Supplies Tracker</span>
      <iframe src="/frames/iphone-15-pro.html?screen=screens/04-supplies.html" loading="lazy"></iframe>
    </div>
    <div class="frame-container">
